-- Supabase schema mirroring src/data/mock.js.
-- Run in the Supabase SQL editor when you're ready to leave mock mode.
-- After running, set VITE_SUPABASE_URL + VITE_SUPABASE_ANON_KEY in .env.local
-- and the app switches to live data automatically.

create table if not exists users (
  id uuid primary key default gen_random_uuid(),
  name text not null,
  avatar text,
  points int not null default 0,
  level int not null default 1,
  streak int not null default 0,
  created_at timestamptz default now()
);

create table if not exists badges (
  id uuid primary key default gen_random_uuid(),
  name text not null,
  icon text,
  description text,
  earned boolean default false
);

create table if not exists quests (
  id uuid primary key default gen_random_uuid(),
  title text not null,
  points int not null default 0,
  status text not null default 'todo' -- todo | in_progress | done
);

create table if not exists agents (
  id uuid primary key default gen_random_uuid(),
  name text not null,
  description text,
  status text default 'idle',
  model text,
  runs int default 0
);

create table if not exists mcp_servers (
  id uuid primary key default gen_random_uuid(),
  name text not null,
  description text,
  connected boolean default false,
  tools int default 0
);

create table if not exists connectors (
  id text primary key default gen_random_uuid()::text,
  name text not null,
  description text,
  icon_url text,
  featured boolean default true,
  connected boolean default false,
  tools int default 0,
  category text,
  created_at timestamptz default now()
);

create table if not exists agent_runs (
  id uuid primary key default gen_random_uuid(),
  agent text not null,
  step text not null,
  at text,
  created_at timestamptz default now()
);

create table if not exists customers (
  id text primary key default gen_random_uuid()::text,
  name text not null,
  contact text,
  email text,
  phone text,
  avatar text,
  accent text,
  status text not null default 'Monitoring',
  tier text,
  seats int,
  value text,
  last_touch text,
  next_action text,
  task text,
  due text,
  overdue boolean not null default false,
  tags text[] not null default '{}',
  contact_name text,
  date_of_birth date,
  gender text,
  marital_status text,
  occupation text,
  dependents int,
  nationality text,
  assigned_advisor_id text,
  client_since_date date,
  acquisition_channel text,
  referred_by text,
  annual_income_bracket text,
  net_worth_bracket text,
  risk_tolerance text,
  investment_horizon_years int,
  liabilities_summary text,
  policies jsonb not null default '[]'::jsonb,
  has_will boolean,
  estate_plan_status text,
  business_ownership boolean,
  intended_heirs text,
  life_events jsonb not null default '[]'::jsonb,
  last_contact_date date,
  preferred_communication_channel text,
  rapport_notes text,
  kyc_status text,
  last_fact_find_date date,
  consent_marketing boolean,
  policy_count int,
  policy_summary text,
  next_renewal date,
  next_renewal_policy_type text,
  next_life_event text,
  next_life_event_date date,
  updated_at timestamptz,
  created_at timestamptz default now()
);

alter table customers add column if not exists phone text;
alter table customers add column if not exists contact_name text;
